    fun cacheManager(connectionFactory: RedisConnectionFactory): CacheManager {
        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeKeysWith(RedisSerializationContext.SerializationPair.fromSerializer(StringRedisSerializer()))
            .serializeValuesWith(RedisSerializationContext.SerializationPair.fromSerializer(GenericJackson2JsonRedisSerializer()))
            .disableCachingNullValues()

        val cacheConfigs = mapOf(
            "userProfile"         to defaultConfig.entryTtl(Duration.ofMinutes(30)),
            "userSummary"         to defaultConfig.entryTtl(Duration.ofHours(1)),
            "followCount"         to defaultConfig.entryTtl(Duration.ofMinutes(5)),
            "followStatus"        to defaultConfig.entryTtl(Duration.ofMinutes(10)),
            "productList"         to defaultConfig.entryTtl(Duration.ofDays(1)),
            "notificationSetting" to defaultConfig.entryTtl(Duration.ofMinutes(30)),
            "likeCount"           to defaultConfig.entryTtl(Duration.ofMinutes(1)),
            "commentCount"        to defaultConfig.entryTtl(Duration.ofMinutes(2)),
        )

        return RedisCacheManager.builder(connectionFactory)
            .cacheDefaults(defaultConfig.entryTtl(Duration.ofMinutes(10)))
            .withInitialCacheConfigurations(cacheConfigs)
            .build()
    }
}
