### 프로필 서비스 캐시 적용 (N+1 핵심 해결)

```kotlin
// Before: 캐시 없음, 피드 렌더링 시 N번 DB 조회
@Service
@Transactional(readOnly = true)
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    fun getProfile(userId: String): UserProfileDto {
        val user = userRepository.findById(userId).orElseThrow()
        val profile = profileRepository.findByUserId(userId) // 매번 DB 조회
        return UserProfileDto.from(user, profile)
    }
}

// After: @Cacheable 적용, 동일 userId 재요청 시 Redis에서 응답
@Service
@Transactional(readOnly = true)
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    @Cacheable(cacheNames = ["userProfile"], key = "#userId")
    fun getProfile(userId: String): UserProfileDto {
        val user = userRepository.findById(userId).orElseThrow()
        val profile = profileRepository.findByUserId(userId)
        return UserProfileDto.from(user, profile)
    }

    // 피드용 경량 조회 (이름+이미지만)
    @Cacheable(cacheNames = ["userSummary"], key = "#userId")
    fun getUserSummary(userId: String): UserSummaryDto {
        return userRepository.findSummaryById(userId)
            ?: throw EntityNotFoundException("user not found: $userId")
    }
}
```

